import { component$, Slot } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { categories, findCategory, findPage } from "~/data/docs";
import { Breadcrumb, type Crumb } from "~/components/breadcrumb/breadcrumb";
import { Sidebar } from "~/components/sidebar/sidebar";

/**
 * Lightweight list of categories (slug + title) used to render the
 * sidebar navigation. Resolved on the server from the local data module.
 */
export const useDocsCategories = routeLoader$(() => {
  return categories.map((category) => ({
    slug: category.slug,
    title: category.title,
  }));
});

/**
 * Builds the breadcrumb trail for the current request based on the
 * `category` / `slug` route params. Always starts with a `Docs` crumb.
 *
 * Note: unknown category/page slugs are turned into a 404 response by the
 * nested `[category]/layout.tsx` and `[category]/[slug]/layout.tsx` loaders,
 * so the fallback labels here are only ever used transiently.
 */
export const useBreadcrumbTrail = routeLoader$((requestEvent): Crumb[] => {
  const { category: categorySlug, slug: pageSlug } = requestEvent.params;
  const crumbs: Crumb[] = [{ label: "Docs", href: "/docs" }];

  if (categorySlug) {
    const category = findCategory(categorySlug);
    crumbs.push({
      label: category?.title ?? categorySlug,
      href: `/docs/${categorySlug}`,
    });

    if (pageSlug) {
      const page = category ? findPage(categorySlug, pageSlug) : undefined;
      crumbs.push({
        label: page?.title ?? pageSlug,
        href: `/docs/${categorySlug}/${pageSlug}`,
      });
    }
  }

  return crumbs;
});

export default component$(() => {
  const crumbs = useBreadcrumbTrail();
  const docsCategories = useDocsCategories();

  return (
    <div class="docs-layout">
      <Breadcrumb crumbs={crumbs.value} />
      <div class="docs-body">
        <Sidebar categories={docsCategories.value} />
        <main class="docs-content">
          <Slot />
        </main>
      </div>
    </div>
  );
});

import { component$, Slot } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { findCategory } from "~/data/docs";

/**
 * Resolves the current category from the local data module. Requesting an
 * unknown category responds with a 404, guarding every route nested under
 * `/docs/[category]`.
 */
export const useCategoryData = routeLoader$((requestEvent) => {
  const category = findCategory(requestEvent.params.category);

  if (!category) {
    throw requestEvent.fail(404, {
      message: `Category "${requestEvent.params.category}" not found`,
    });
  }

  return category;
});

export default component$(() => {
  return <Slot />;
});

import { component$, Slot } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { findPage } from "~/data/docs";

/**
 * Resolves the current page from the local data module. Requesting an
 * unknown page slug (within a valid category) responds with a 404.
 */
export const usePageData = routeLoader$((requestEvent) => {
  const page = findPage(requestEvent.params.category, requestEvent.params.slug);

  if (!page) {
    throw requestEvent.fail(404, {
      message: `Page "${requestEvent.params.slug}" not found`,
    });
  }

  return page;
});

export default component$(() => {
  return <Slot />;
});

import { component$ } from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";
import { useDocsCategories } from "./layout";

export default component$(() => {
  const categories = useDocsCategories();

  return (
    <div>
      <h1>Documentation</h1>
      <ul class="category-list">
        {categories.value.map((category) => (
          <li key={category.slug}>
            <a href={`/docs/${category.slug}`}>{category.title}</a>
          </li>
        ))}
      </ul>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Docs",
  meta: [
    {
      name: "description",
      content: "Browse the documentation categories.",
    },
  ],
};

import { component$ } from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";
import { useCategoryData } from "./layout";

export default component$(() => {
  const category = useCategoryData();

  return (
    <div>
      <h1>{category.value.title}</h1>
      <ul class="page-list">
        {category.value.pages.map((page) => (
          <li key={page.slug}>
