import { component$ } from "@builder.io/qwik";

export interface Crumb {
  label: string;
  href: string;
}

interface BreadcrumbProps {
  crumbs: Crumb[];
}

export const Breadcrumb = component$<BreadcrumbProps>(({ crumbs }) => {
  return (
    <nav aria-label="breadcrumb" class="breadcrumb">
      <ol class="breadcrumb-list">
        {crumbs.map((crumb, index) => {
          const isLast = index === crumbs.length - 1;
          return (
            <li key={crumb.href} class="breadcrumb-item">
              {isLast ? (
                <span aria-current="page">{crumb.label}</span>
              ) : (
                <a href={crumb.href}>{crumb.label}</a>
              )}
              {!isLast && <span class="breadcrumb-separator"> / </span>}
            </li>
          );
        })}
      </ol>
    </nav>
  );
});

import { component$ } from "@builder.io/qwik";
import { useLocation } from "@builder.io/qwik-city";

interface SidebarCategory {
  slug: string;
  title: string;
}

interface SidebarProps {
  categories: SidebarCategory[];
}

export const Sidebar = component$<SidebarProps>(({ categories }) => {
  const location = useLocation();
  const activeCategorySlug = location.params.category;

  return (
    <nav aria-label="sidebar" class="sidebar">
      <ul class="sidebar-list">
        {categories.map((category) => {
          const isActive = category.slug === activeCategorySlug;
          return (
            <li key={category.slug}>
              <a
                href={`/docs/${category.slug}`}
                aria-current={isActive ? "page" : undefined}
              >
                {category.title}
              </a>
            </li>
          );
        })}
      </ul>
    </nav>
  );
});

